import{_ as t}from"./chunks/11-tui-workspace-setup.MCQvk2sM.js";import{_ as a,o as r,c as o,a2 as s}from"./chunks/framework.DTa47_fH.js";const m=JSON.parse('{"title":"Workspace Setup","description":"","frontmatter":{},"headers":[],"relativePath":"workspace-setup.md","filePath":"workspace-setup.md"}'),i={name:"workspace-setup.md"};function n(l,e,p,d,c,h){return r(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="workspace-setup" tabindex="-1">Workspace Setup <a class="header-anchor" href="#workspace-setup" aria-label="Permalink to &quot;Workspace Setup&quot;">​</a></h1><p>Workspace Setup is the guided starting point for every SWAO engagement. It walks you through seven steps -- from creating the workspace folder to connecting Claude Desktop -- and leaves you with a fully configured environment ready to run your first assessment.</p><p>Access it from the TUI main menu by pressing <strong>1</strong>, or by running <code>swao</code> from your workspace directory and selecting Workspace Setup.</p><p><img src="'+t+'" alt="SWAO Workspace Setup wizard"></p><hr><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>A workspace is a single folder that contains everything SWAO needs for one engagement: the compliance framework catalogues, your application source references, ingested context documents, assessment outputs, and the Power BI export bundle. The Setup wizard creates and configures this folder in one guided flow.</p><hr><h2 id="the-seven-steps" tabindex="-1">The seven steps <a class="header-anchor" href="#the-seven-steps" aria-label="Permalink to &quot;The seven steps&quot;">​</a></h2><h3 id="step-1-initialise-workspace" tabindex="-1">Step 1 -- Initialise Workspace <a class="header-anchor" href="#step-1-initialise-workspace" aria-label="Permalink to &quot;Step 1 -- Initialise Workspace&quot;">​</a></h3><p>Creates the <code>.swao.yml</code> configuration file for a new workspace, or reconnects to an existing one. Enter the directory path (or press Enter to use the current directory). Existing workspaces are detected automatically so you can continue where you left off.</p><h3 id="step-2-llm-provider" tabindex="-1">Step 2 -- LLM Provider <a class="header-anchor" href="#step-2-llm-provider" aria-label="Permalink to &quot;Step 2 -- LLM Provider&quot;">​</a></h3><p>Configures the large language model SWAO uses for its analysis passes. Supported providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Notes</th></tr></thead><tbody><tr><td>Anthropic Claude</td><td>Default. Recommended for sovereign workloads (zero-retention endpoint available).</td></tr><tr><td>Azure OpenAI</td><td>Use for deployments inside an Azure tenant with EU data residency.</td></tr><tr><td>OpenAI</td><td>GPT-4o and above.</td></tr><tr><td>Ollama (local)</td><td>Fully air-gapped option -- no data leaves the machine.</td></tr></tbody></table><p>You will need an API key for cloud providers. Ollama requires a locally running Ollama server.</p><h3 id="step-3-credentials" tabindex="-1">Step 3 -- Credentials <a class="header-anchor" href="#step-3-credentials" aria-label="Permalink to &quot;Step 3 -- Credentials&quot;">​</a></h3><p>Stores API keys and repository credentials securely. Credentials are written to the workspace credential store (never to <code>.swao.yml</code> directly) and are resolved at runtime. This step also covers VCS authentication for private repositories that SWAO will clone during assessment.</p><h3 id="step-4-health-check" tabindex="-1">Step 4 -- Health Check <a class="header-anchor" href="#step-4-health-check" aria-label="Permalink to &quot;Step 4 -- Health Check&quot;">​</a></h3><p>Runs the full 11-probe Health Check automatically at the end of setup to confirm every component is working. Any probe that reports WARN or INFO includes guidance on how to resolve it. You can re-run Health Check at any time from menu item 2.</p><h3 id="step-5-mcp-client" tabindex="-1">Step 5 -- MCP Client <a class="header-anchor" href="#step-5-mcp-client" aria-label="Permalink to &quot;Step 5 -- MCP Client&quot;">​</a></h3><p>Configures the SWAO MCP server entry in Claude Desktop so that Claude can call SWAO assessment tools directly from a conversation. SWAO writes the server configuration automatically -- you just confirm the Claude Desktop path.</p><h3 id="step-6-playwright" tabindex="-1">Step 6 -- Playwright <a class="header-anchor" href="#step-6-playwright" aria-label="Permalink to &quot;Step 6 -- Playwright&quot;">​</a></h3><p>Verifies that Playwright and Chromium are installed. Playwright is required only for PDF report generation and for the HTML Editor publication path. If Playwright is absent, SWAO skips those steps gracefully and still produces all other outputs.</p><h3 id="step-7-ready" tabindex="-1">Step 7 -- Ready <a class="header-anchor" href="#step-7-ready" aria-label="Permalink to &quot;Step 7 -- Ready&quot;">​</a></h3><p>Confirms the workspace is fully configured and displays the next recommended action (usually &quot;Run Assessment&quot; or &quot;Health Check&quot;).</p><hr><h2 id="after-setup" tabindex="-1">After setup <a class="header-anchor" href="#after-setup" aria-label="Permalink to &quot;After setup&quot;">​</a></h2><p>Once setup is complete your workspace contains:</p><ul><li><code>.swao.yml</code> -- the workspace configuration file. Open this to review or change any setting.</li><li><code>wsp/inputs/catalogs/community/</code> -- the installed compliance framework YAML files.</li><li><code>wsp/templates/powerbi/</code> -- the Power BI <code>.pbit</code> template files for single-app and portfolio reporting.</li><li><code>apps/&lt;app-id&gt;/ingestion/</code> -- the drop folder for context documents (architecture reviews, CMDB exports, workshop transcripts).</li></ul><hr><h2 id="re-running-setup" tabindex="-1">Re-running setup <a class="header-anchor" href="#re-running-setup" aria-label="Permalink to &quot;Re-running setup&quot;">​</a></h2><p>You can re-run Setup at any time. It detects existing configuration and offers to update individual steps without overwriting the rest. This is useful when you need to rotate an API key, add a new LLM provider, or reconnect MCP after a Claude Desktop update.</p>',32)])])}const g=a(i,[["render",n]]);export{m as __pageData,g as default};
